mapper.select:
SELECT
    *
FROM afm_file_exif AS a
    LEFT JOIN afm_image_dup_assoc AS b ON a.exif_id = b.assoc_exif_id
WHERE
    a.is_deleted = 0
    AND a.source_sys != 'AFM'
    AND b.dup_note_id = #{noteId}
    AND b.similarity >= #{fileSimilarity}

    AND a.exif_id != #{exifId}


    AND a.file_index != #{fileIndex}


    AND a.type = #{type}

ORDER BY b.similarity DESC
